/**
 * Decoding module: converts encoded integers to display strings
 */

import {
	isCountBasedScheme,
	isDistanceBasedScheme,
	isLoadBasedScheme,
	isTimeBasedScheme,
} from "../constants"
import type { DistanceUnit, FormatOptions, WorkoutScheme } from "../types"
import { decodeDistance, mmToUnit } from "./distance"
import { decodeLoad, gramsToUnit } from "./load"
import { decodeRoundsReps } from "./rounds-reps"
import { decodeTime, decodeTimeToSeconds } from "./time"

export { decodeDistance, mmToUnit } from "./distance"
export { decodeLoad, gramsToUnit } from "./load"
export { decodeRoundsReps, extractRoundsReps } from "./rounds-reps"
// Re-export individual decoders
export { decodeTime, decodeTimeToSeconds } from "./time"

/**
 * Decode an encoded score to a display string based on the scheme.
 *
 * @param value - Encoded integer value
 * @param scheme - Workout scheme determining decoding method
 * @param options - Optional format options
 *
 * @example
 * decodeScore(754000, "time")                      // → "12:34"
 * decodeScore(754567, "time")                      // → "12:34.567"
 * decodeScore(500012, "rounds-reps")               // → "5+12"
 * decodeScore(102058, "load", { weightUnit: "lbs", includeUnit: true }) // → "225 lbs"
 * decodeScore(5000000, "meters", { includeUnit: true }) // → "5000m"
 * decodeScore(150, "reps")                         // → "150"
 */
export function decodeScore(
	value: number,
	scheme: WorkoutScheme,
	options?: FormatOptions,
): string {
	// Time-based schemes
	// Show ms if non-zero, or if alwaysShowMs option is set
	if (isTimeBasedScheme(scheme)) {
		return decodeTime(value, {
			alwaysShowMs: options?.compact === false, // Show .000 when not compact
		})
	}

	// Rounds + Reps
	if (scheme === "rounds-reps") {
		return decodeRoundsReps(value, { compact: options?.compact })
	}

	// Load (weight)
	if (isLoadBasedScheme(scheme)) {
		return decodeLoad(value, {
			unit: options?.weightUnit ?? "lbs",
			includeUnit: options?.includeUnit,
		})
	}

	// Distance
	if (isDistanceBasedScheme(scheme)) {
		const defaultUnit: DistanceUnit = scheme === "feet" ? "ft" : "m"
		return decodeDistance(value, {
			unit: options?.distanceUnit ?? defaultUnit,
			includeUnit: options?.includeUnit,
		})
	}

	// Count-based schemes (reps, calories, points)
	if (isCountBasedScheme(scheme)) {
		const suffix = getCountSuffix(scheme, options?.includeUnit)
		return suffix ? `${value}${suffix}` : value.toString()
	}

	// Pass/fail
	if (scheme === "pass-fail") {
		return value === 1 ? "Pass" : "Fail"
	}

	return value.toString()
}

/**
 * Get the unit suffix for count-based schemes.
 */
function getCountSuffix(scheme: WorkoutScheme, includeUnit?: boolean): string {
	if (!includeUnit) return ""

	switch (scheme) {
		case "reps":
			return " reps"
		case "calories":
			return " cal"
		case "points":
			return " pts"
		default:
			return ""
	}
}

/**
 * Decode to a numeric value in the original unit.
 * Useful when you need the raw number for calculations.
 *
 * @param value - Encoded integer value
 * @param scheme - Workout scheme
 * @param options - Format options (for unit preferences)
 *
 * @example
 * decodeToNumber(754567, "time")    // → 754.567 (seconds)
 * decodeToNumber(102058, "load", { weightUnit: "lbs" }) // → 225
 */
export function decodeToNumber(
	value: number,
	scheme: WorkoutScheme,
	options?: FormatOptions,
): number {
	// Time-based: return seconds
	if (isTimeBasedScheme(scheme)) {
		return decodeTimeToSeconds(value)
	}

	// Load: return in specified unit
	if (isLoadBasedScheme(scheme)) {
		return gramsToUnit(value, options?.weightUnit ?? "lbs")
	}

	// Distance: return in specified unit
	if (isDistanceBasedScheme(scheme)) {
		const defaultUnit: DistanceUnit = scheme === "feet" ? "ft" : "m"
		return mmToUnit(value, options?.distanceUnit ?? defaultUnit)
	}

	// All others: return as-is
	return value
}

/**
 * Core type definitions for the scoring library
 */

// ============ Scheme & Status Constants ============

export const WORKOUT_SCHEMES = [
	"time",
	"time-with-cap",
	"rounds-reps",
	"reps",
	"emom",
	"load",
	"calories",
	"meters",
	"feet",
	"points",
	"pass-fail",
] as const
export type WorkoutScheme = (typeof WORKOUT_SCHEMES)[number]

export const SCORE_STATUSES = ["scored", "cap", "dq", "withdrawn"] as const
export type ScoreStatus = (typeof SCORE_STATUSES)[number]

export const SCORE_TYPES = [
	"min",
	"max",
	"sum",
	"average",
	"first",
	"last",
] as const
export type ScoreType = (typeof SCORE_TYPES)[number]

export const TIEBREAK_SCHEMES = ["time", "reps"] as const
export type TiebreakScheme = (typeof TIEBREAK_SCHEMES)[number]

export type SortDirection = "asc" | "desc"

export const WEIGHT_UNITS = ["lbs", "kg"] as const
export type WeightUnit = (typeof WEIGHT_UNITS)[number]

export const DISTANCE_UNITS = ["m", "km", "ft", "mi"] as const
export type DistanceUnit = (typeof DISTANCE_UNITS)[number]

// ============ Core Score Types ============

/** A single round/set within a score */
export interface ScoreRound {
	roundNumber: number
	/** Encoded value based on scheme */
	value: number
	/** Override scheme for this specific round (rare) */
	schemeOverride?: WorkoutScheme
	/** Status for this specific round */
	status?: ScoreStatus
	/** Secondary value (e.g., reps if this round was capped) */
	secondaryValue?: number
	notes?: string
}

/** Complete score with optional rounds */
export interface Score {
	// Classification
	scheme: WorkoutScheme
	scoreType: ScoreType

	// Primary aggregated value (encoded as integer)
	value: number | null
	status: ScoreStatus

	// Individual rounds (optional)
	rounds?: ScoreRound[]

	// Tiebreak
	tiebreak?: {
		scheme: TiebreakScheme
		value: number
	}

	// Time cap handling (for time-with-cap)
	timeCap?: {
		/** Time cap in milliseconds */
		ms: number
		/** Reps completed when capped */
		secondaryValue: number
	}

	// Computed sort key (for database storage)
	sortKey?: bigint
}

// ============ Input Types ============

/** Input for a single round */
export interface RoundInput {
	/** User input: "225", "12:34", etc. */
	raw: string
	/** Override scheme for this round */
	schemeOverride?: WorkoutScheme
	/** Unit for load/distance */
	unit?: WeightUnit | DistanceUnit
}

/** Input for creating/updating a score */
export interface ScoreInput {
	scheme: WorkoutScheme
	/** Defaults based on scheme if not provided */
	scoreType?: ScoreType

	// Either a single value OR multiple rounds
	/** Single aggregated value (user input string) */
	value?: string
	/** Individual rounds for multi-round workouts */
	rounds?: RoundInput[]

	status?: ScoreStatus

	tiebreak?: {
		raw: string
		scheme: TiebreakScheme
	}

	timeCap?: {
		/** Time cap in milliseconds */
		ms: number
		/** Secondary score if capped (e.g., reps completed) */
		secondaryRaw?: string
	}
}

// ============ Parse Types ============

export interface ParseOptions {
	/** For time schemes: how to interpret raw numbers */
	timePrecision?: "auto" | "seconds" | "ms"
	/** For load/distance schemes */
	unit?: WeightUnit | DistanceUnit
	/** Strict mode rejects ambiguous inputs */
	strict?: boolean
}

export interface ParseResult {
	isValid: boolean
	/** Encoded integer value */
	encoded: number | null
	/** Formatted display string */
	formatted: string
	error?: string
	warnings?: string[]
}

// ============ Format Types ============

export interface FormatOptions {
	/** Hide milliseconds if .000 */
	compact?: boolean
	/** Include unit suffix (e.g., "225 lbs" vs "225") */
	includeUnit?: boolean
	/** Weight display preference */
	weightUnit?: WeightUnit
	/** Distance display preference */
	distanceUnit?: DistanceUnit
	/** Include status prefix (e.g., "CAP", "DQ") */
	showStatus?: boolean
}

// ============ Encode Types ============

export interface EncodeOptions {
	/** Unit for load/distance */
	unit?: WeightUnit | DistanceUnit
}

export interface EncodeRoundsResult {
	/** Encoded values for each round */
	rounds: number[]
	/** Aggregated value based on scoreType */
	aggregated: number | null
}

// ============ Validation Types ============

export interface ValidationResult {
	isValid: boolean
	errors: string[]
	warnings: string[]
}

// ============ Database Record Types ============

/** Database record for scores table */
export interface ScoreRecord {
	id: string
	userId: string
	teamId: string
	workoutId: string
	competitionEventId: string | null
	scheduledWorkoutInstanceId: string | null

	scheme: WorkoutScheme
	scoreType: ScoreType
	scoreValue: number | null

	tiebreakScheme: TiebreakScheme | null
	tiebreakValue: number | null

	timeCapMs: number | null
	// Note: secondaryScheme removed - when capped, score is always reps
	secondaryValue: number | null

	status: ScoreStatus
	statusOrder: number
	sortKey: bigint | null

	scalingLevelId: string | null
	asRx: boolean

	notes: string | null
	recordedAt: number
	createdAt: number
	updatedAt: number
}

/** Database record for score_rounds table */
export interface ScoreRoundRecord {
	id: string
	scoreId: string
	roundNumber: number
	value: number
	schemeOverride: WorkoutScheme | null
	status: ScoreStatus | null
	secondaryValue: number | null
	notes: string | null
	createdAt: number
}

/**
 * Constants and encoding specifications for the scoring library
 */

import type { ScoreStatus, ScoreType, WorkoutScheme } from "./types"

// ============ Status Order for Sorting ============

/**
 * Status order determines sort priority.
 * Lower numbers sort first.
 */
export const STATUS_ORDER: Record<ScoreStatus, number> = {
	scored: 0,
	cap: 1,
	dq: 2,
	withdrawn: 3,
} as const

// ============ Encoding Constants ============

/**
 * Multiplier for rounds+reps encoding.
 * Value = rounds * ROUNDS_REPS_MULTIPLIER + reps
 * Supports up to 99,999 reps per partial round.
 */
export const ROUNDS_REPS_MULTIPLIER = 100_000

/**
 * Maximum score value that fits in the data segment (120 bits).
 * Used for sort key computation to represent null/missing values.
 */
export const MAX_SCORE_VALUE = 2n ** 120n - 1n

// ============ Unit Conversions ============

/**
 * Grams per unit for weight conversions.
 * All weights are stored in grams internally.
 */
export const GRAMS_PER_UNIT = {
	lbs: 453.592,
	kg: 1000,
} as const

/**
 * Millimeters per unit for distance conversions.
 * All distances are stored in millimeters internally.
 */
export const MM_PER_UNIT = {
	m: 1000,
	km: 1_000_000,
	ft: 304.8,
	mi: 1_609_344,
} as const

// ============ Default Score Types ============

/**
 * Default score type (aggregation method) for each workout scheme.
 */
export const DEFAULT_SCORE_TYPES: Record<WorkoutScheme, ScoreType> = {
	time: "min", // Lower time is better
	"time-with-cap": "min", // Lower time is better
	"rounds-reps": "max", // Higher rounds+reps is better
	reps: "max", // Higher reps is better
	emom: "max", // Higher score is better
	load: "max", // Higher load is better
	calories: "max", // Higher calories is better
	meters: "max", // Higher distance is better
	feet: "max", // Higher distance is better
	points: "max", // Higher points is better
	"pass-fail": "first", // First attempt matters
} as const

// ============ Sort Directions ============

/**
 * Sort direction for each workout scheme.
 * 'asc' = lower values sort first (better)
 * 'desc' = higher values sort first (better)
 */
export const SCHEME_SORT_DIRECTIONS: Record<WorkoutScheme, "asc" | "desc"> = {
	time: "asc",
	"time-with-cap": "asc",
	"rounds-reps": "desc",
	reps: "desc",
	emom: "desc",
	load: "desc",
	calories: "desc",
	meters: "desc",
	feet: "desc",
	points: "desc",
	"pass-fail": "desc", // Pass (1) beats Fail (0)
} as const

// ============ Time Constants ============

/** Milliseconds per second */
export const MS_PER_SECOND = 1000
/** Milliseconds per minute */
export const MS_PER_MINUTE = 60 * MS_PER_SECOND
/** Milliseconds per hour */
export const MS_PER_HOUR = 60 * MS_PER_MINUTE

// ============ Scheme Classifications ============

/** Schemes where time is the primary measurement */
export const TIME_BASED_SCHEMES: WorkoutScheme[] = [
	"time",
	"time-with-cap",
	"emom",
]

/** Schemes where weight/load is the primary measurement */
export const LOAD_BASED_SCHEMES: WorkoutScheme[] = ["load"]

/** Schemes where distance is the primary measurement */
export const DISTANCE_BASED_SCHEMES: WorkoutScheme[] = ["meters", "feet"]

/** Schemes that are simple integer counts */
export const COUNT_BASED_SCHEMES: WorkoutScheme[] = [
	"reps",
	"calories",
	"points",
]

/**
 * Check if a scheme is time-based
 */
export function isTimeBasedScheme(scheme: WorkoutScheme): boolean {
	return TIME_BASED_SCHEMES.includes(scheme)
}

/**
 * Check if a scheme is load-based
 */
export function isLoadBasedScheme(scheme: WorkoutScheme): boolean {
	return LOAD_BASED_SCHEMES.includes(scheme)
}

/**
 * Check if a scheme is distance-based
 */
export function isDistanceBasedScheme(scheme: WorkoutScheme): boolean {
	return DISTANCE_BASED_SCHEMES.includes(scheme)
}

/**
 * Check if a scheme is a simple count
 */
export function isCountBasedScheme(scheme: WorkoutScheme): boolean {
	return COUNT_BASED_SCHEMES.includes(scheme)
}

