			// When focus moves to the iframe, reclaim it after a tick
			setTimeout(() => {
				if (document.activeElement?.tagName === "IFRAME") {
					window.focus()
				}
			}, 0)
		}
		window.addEventListener("blur", handleBlur)
		return () => window.removeEventListener("blur", handleBlur)
	}, [])

